parameters.jsCode:
// Extrair e validar a resposta JSON do Ollama
const respostaOllama = $input.first().json;
const resumeId = $('Webhook — Receber CV').first().json.body.resume_id;

let analise;
try {
  // O Ollama com format:json retorna o campo 'response'
  const textoResposta = respostaOllama.response || respostaOllama.text || '{}';
  analise = JSON.parse(textoResposta);
} catch (e) {
  // Fallback em caso de JSON mal formado
  analise = {
    score: 50,
    skills: 'Não foi possível extrair as competências',
    feedback: 'A análise automática falhou. Reveja o currículo manualmente.'
  };
}

// Garantir tipos correctos
const score = Math.min(100, Math.max(0, parseFloat(analise.score || 50)));
const skills = String(analise.skills || '').trim();
const feedback = String(analise.feedback || '').trim();

return [{ json: { resume_id: resumeId, score, skills, feedback } }];
